import React, { useState } from 'react';
import Home from './Home';
import FarmerAdd from './FarmerAdd';

function App() {
  const [screen, setScreen] = useState('home'); // 'home' or 'sell'

  return (
    <div className="min-h-screen">
      {screen === 'home' && <Home onSellClick={() => setScreen('sell')} />}
      {screen === 'sell' && <FarmerAdd onBack={() => setScreen('home')} />}
    </div>
  );
}

export default App;
